import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { experiencesService } from '../services/experiences';
import './CreateExperience.css';

const CreateExperience = () => {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user') || 'null');

  const [form, setForm] = useState({
    title            : '',
    description      : '',
    price            : '',
    discount_price   : '',
    instructor_cut   : '70',
    college_cut      : '30',
    preview_video_url: '',
    image            : null,
    status           : 'draft',
  });
  const [imagePreview, setImagePreview] = useState(null);
  const [submitting, setSubmitting]     = useState(false);
  const [errors, setErrors]             = useState({});

  if (!user || !user.is_instructor) {
    navigate('/');
    return null;
  }

  const handle = (e) => {
    const { name, value, files } = e.target;
    if (files) {
      setForm(p => ({ ...p, [name]: files[0] }));
      setImagePreview(URL.createObjectURL(files[0]));
    } else {
      setForm(p => ({ ...p, [name]: value }));
      if (name === 'instructor_cut') {
        const ic = parseFloat(value) || 0;
        setForm(p => ({ ...p, instructor_cut: value, college_cut: String(100 - ic) }));
      }
    }
  };

  const validate = () => {
    const e = {};
    if (!form.title.trim())        e.title = 'أدخل عنوان التجربة';
    if (!form.price)               e.price = 'أدخل السعر';
    if (parseFloat(form.price) < 0) e.price = 'السعر لا يمكن أن يكون سالباً';
    if (form.discount_price && parseFloat(form.discount_price) >= parseFloat(form.price))
      e.discount_price = 'سعر الخصم يجب أن يكون أقل من السعر الأصلي';
    if (parseFloat(form.instructor_cut) + parseFloat(form.college_cut) !== 100)
      e.instructor_cut = 'مجموع النسب يجب أن يساوي 100%';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const submit = async (e, publishNow = false) => {
    e.preventDefault();
    if (!validate()) return;
    setSubmitting(true);
    try {
      const fd = new FormData();
      fd.append('title',             form.title);
      fd.append('description',       form.description);
      fd.append('price',             form.price);
      fd.append('instructor_cut',    form.instructor_cut);
      fd.append('college_cut',       form.college_cut);
      fd.append('status',            publishNow ? 'published' : 'draft');
      if (form.discount_price)       fd.append('discount_price',    form.discount_price);
      if (form.preview_video_url)    fd.append('preview_video_url', form.preview_video_url);
      if (form.image)                fd.append('image',             form.image);

      await experiencesService.create(fd);
      alert(publishNow ? '✅ تم النشر!' : '✅ تم الحفظ كمسودة');
      navigate('/experiences');
    } catch (err) {
      const data = err.response?.data;
      if (data && typeof data === 'object') setErrors(data);
      else alert('حدث خطأ: ' + (err.response?.data?.detail || 'حاول مرة أخرى'));
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="exp-page">
      <div className="exp-container">

        <div className="exp-page-header">
          <h1 className="exp-title">إنشاء تجربة جديدة 🧪</h1>
          <p className="exp-subtitle">أضف محتواك وانتظر موافقة الإدارة</p>
        </div>

        <form>

          {/* ── معلومات أساسية ── */}
          <div className="exp-card">
            <div className="exp-card-header">
              <span className="exp-card-icon">📋</span>
              <h2>المعلومات الأساسية</h2>
            </div>

            <div className="exp-field">
              <label>عنوان التجربة <span className="req">*</span></label>
              <input className="exp-input" name="title" value={form.title}
                onChange={handle} placeholder="مثال: حل تمارين الـ Recursion" required />
              {errors.title && <p className="exp-error">{errors.title}</p>}
            </div>

            <div className="exp-field">
              <label>وصف التجربة</label>
              <textarea className="exp-input exp-textarea" name="description"
                value={form.description} onChange={handle} rows={4}
                placeholder="اشرح ما سيستفيد منه الطالب..." />
            </div>

            <div className="exp-field">
              <label>رابط فيديو معاينة مجاني (اختياري)</label>
              <input className="exp-input" name="preview_video_url"
                value={form.preview_video_url} onChange={handle}
                placeholder="https://youtube.com/embed/..." />
            </div>

            <div className="exp-field">
              <label>صورة الغلاف</label>
              <div className="exp-image-upload">
                {imagePreview ? (
                  <div className="image-preview-wrap">
                    <img src={imagePreview} alt="preview" className="image-preview" />
                    <label className="image-change-btn">
                      تغيير الصورة
                      <input type="file" name="image" accept="image/*"
                        onChange={handle} hidden />
                    </label>
                  </div>
                ) : (
                  <label className="image-drop-zone">
                    <span className="drop-icon">🖼️</span>
                    <span className="drop-text">اختر صورة الغلاف</span>
                    <input type="file" name="image" accept="image/*"
                      onChange={handle} hidden />
                  </label>
                )}
              </div>
            </div>
          </div>

          {/* ── التسعير ── */}
          <div className="exp-card">
            <div className="exp-card-header">
              <span className="exp-card-icon">💰</span>
              <h2>التسعير وتوزيع الأرباح</h2>
            </div>

            <div className="exp-field-row">
              <div className="exp-field">
                <label>السعر (EGP) <span className="req">*</span></label>
                <input className="exp-input" type="number" name="price"
                  value={form.price} onChange={handle} min="0" placeholder="0" />
                {errors.price && <p className="exp-error">{errors.price}</p>}
              </div>
              <div className="exp-field">
                <label>السعر بعد الخصم (اختياري)</label>
                <input className="exp-input" type="number" name="discount_price"
                  value={form.discount_price} onChange={handle} min="0"
                  placeholder="اتركه فارغاً لو مفيش خصم" />
                {errors.discount_price && <p className="exp-error">{errors.discount_price}</p>}
              </div>
            </div>

            <div className="exp-field">
              <label>توزيع الأرباح %</label>
              <div className="exp-split-wrap">
                <div className="exp-split-item">
                  <label className="exp-split-label">حصة المدرس %</label>
                  <input className="exp-input duration-input" type="number"
                    name="instructor_cut" value={form.instructor_cut}
                    onChange={handle} min="0" max="100" />
                </div>
                <span className="exp-split-plus">+</span>
                <div className="exp-split-item">
                  <label className="exp-split-label">حصة الكلية %</label>
                  <input className="exp-input duration-input" type="number"
                    value={form.college_cut} readOnly
                    style={{ opacity: 0.6 }} />
                </div>
                <span className="exp-split-eq">= 100%</span>
              </div>
              {errors.instructor_cut && <p className="exp-error">{errors.instructor_cut}</p>}
            </div>
          </div>

          {/* ── أزرار ── */}
          <div className="exp-submit-row">
            <button type="button" className="exp-btn-cancel"
              onClick={() => navigate(-1)}>
              إلغاء
            </button>
            <button type="button" className="exp-btn-cancel"
              onClick={(e) => submit(e, false)} disabled={submitting}>
              💾 حفظ كمسودة
            </button>
            <button type="button" className="exp-btn-submit"
              onClick={(e) => submit(e, true)} disabled={submitting}>
              {submitting ? 'جاري الإنشاء...' : '🚀 نشر الآن'}
            </button>
          </div>

        </form>
      </div>
    </div>
  );
};

export default CreateExperience;
